{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This is a classic textbook example of the Ritter reaction, demonstrating the formation of a stable tert-butyl carbocation from tert-butanol under strong acid (sulfuric acid) catalysis. This carbocation is then trapped by acetonitrile, which, upon hydrolysis, yields N-tert-butylacetamide. All reactants and products are simple, acyclic, and lack complex functional groups, making it a clear and unambiguous representation of the core transformation.",
    "collision_avoidance_note": "The use of simple, acyclic aliphatic substrates (tert-butanol and acetonitrile) avoids overlap with other named reactions involving aromatic rings, complex rearrangements, or specific functional groups. The reaction is a straightforward addition/hydrolysis sequence, distinct from rearrangements (like Beckmann) or condensations involving carbonyls."
  }
}
